--
-- Structure for view `account_current_balances`
--
DROP TABLE IF EXISTS `account_current_balances`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `account_current_balances`  AS SELECT `a`.`id` AS `id`, `a`.`account_name` AS `account_name`, `a`.`account_type_id` AS `account_type_id`, `a`.`bank_name` AS `bank_name`, `a`.`account_number` AS `account_number`, `a`.`status` AS `status`, `a`.`interest_rate` AS `interest_rate`, `a`.`minimum_balance` AS `minimum_balance`, `a`.`notes` AS `notes`, `a`.`created_at` AS `created_at`, `a`.`last_updated` AS `last_updated`, coalesce(`bh`.`balance`,0) AS `current_balance`, `bh`.`month_year` AS `last_balance_update`, `bh`.`growth_amount` AS `growth_amount`, `bh`.`growth_percentage` AS `growth_percentage` FROM (`accounts` `a` left join `balance_history` `bh` on(`a`.`id` = `bh`.`account_id` and `bh`.`month_year` = (select max(`bh2`.`month_year`) from `balance_history` `bh2` where `bh2`.`account_id` = `a`.`id`)))  ;

