CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `account_type_distribution`  AS SELECT `at`.`type_name` AS `account_type`, `at`.`color_code` AS `color_code`, `at`.`icon_class` AS `icon_class`, count(distinct `a`.`id`) AS `account_count`, coalesce(sum(`latest_balance`.`balance`),0) AS `total_balance`, coalesce(avg(`latest_balance`.`balance`),0) AS `average_balance`, CASE WHEN (select sum(`bh2`.`balance`) from ((`balance_history` `bh2` join (select `balance_history`.`account_id` AS `account_id`,max(`balance_history`.`month_year`) AS `max_month` from `balance_history` group by `balance_history`.`account_id`) `latest` on(`bh2`.`account_id` = `latest`.`account_id` AND `bh2`.`month_year` = `latest`.`max_month`)) join `accounts` `a2` on(`bh2`.`account_id` = `a2`.`id`)) where `a2`.`status` = 'Active' AND `bh2`.`balance` > 0) > 0 THEN coalesce(sum(`latest_balance`.`balance`),0) / (select sum(`bh2`.`balance`) from ((`balance_history` `bh2` join (select `balance_history`.`account_id` AS `account_id`,max(`balance_history`.`month_year`) AS `max_month` from `balance_history` group by `balance_history`.`account_id`) `latest` on(`bh2`.`account_id` = `latest`.`account_id` and `bh2`.`month_year` = `latest`.`max_month`)) join `accounts` `a2` on(`bh2`.`account_id` = `a2`.`id`)) where `a2`.`status` = 'Active' and `bh2`.`balance` > 0) * 100 ELSE 0 END AS `percentage` FROM ((`account_types` `at` left join `accounts` `a` on(`at`.`id` = `a`.`account_type_id` and `a`.`status` = 'Active')) left join (select `bh`.`account_id` AS `account_id`,`bh`.`balance` AS `balance` from (`balance_history` `bh` join (select `balance_history`.`account_id` AS `account_id`,max(`balance_history`.`month_year`) AS `max_month` from `balance_history` group by `balance_history`.`account_id`) `latest` on(`bh`.`account_id` = `latest`.`account_id` and `bh`.`month_year` = `latest`.`max_month`))) `latest_balance` on(`a`.`id` = `latest_balance`.`account_id`)) GROUP BY `at`.`id`, `at`.`type_name`, `at`.`color_code`, `at`.`icon_class` HAVING `account_count` > 0 ORDER BY coalesce(sum(`latest_balance`.`balance`),0) AS `DESCdesc` ASC  ;

